// Use a private RPC for the wallet client
const walletClient = createWalletClient({
  account, chain: mainnet,
  transport: http('https://rpc.flashbots.net/fast')  // or MEV-Blocker, Eden
});

// Enforce tight slippage at swap time
const quote = await getQuote(tokenIn, tokenOut, amountIn);
const slippageBps = stableToStable ? 50n : 100n;
const amountOutMin = (quote * (10000n - slippageBps)) / 10000n;

// Reject if quote moved more than tolerance
const freshQuote = await getQuote(tokenIn, tokenOut, amountIn);
if (freshQuote < amountOutMin) throw new Error('Slippage violation — abort');
